insert into public.sys_fin_direction_cd (direction_code,name,name2,description,description2,affects_cash_in,affects_cash_out,is_neutral,display_order) values
('IN','In','داخل','Money/value moves into business or receivable is reduced by collection.','حركة مالية داخلة أو تحصيل يقلل الرصيد المستحق.',true,false,false,10),
('OUT','Out','خارج','Money/value moves out of business, such as refunds, expenses, or supplier payments.','حركة مالية خارجة مثل مردودات أو مصاريف أو مدفوعات موردين.',false,true,false,20),
('NEUTRAL','Neutral','محايد','No cash/bank movement now; may still affect stored value or outstanding balance.','لا توجد حركة نقدية أو بنكية حالياً مع إمكانية التأثير على الأرصدة أو المستحقات.',false,false,true,30)
insert into public.sys_payment_method_cd (payment_method_code,name,name2,description,description2,payment_method_family,payment_nature,is_cash,is_card,is_bank,is_check,is_mobile,is_gateway,is_digital,requires_cash_drawer,requires_reference,requires_external_confirmation,supports_authorization,supports_capture,supports_refund,supports_void,supports_partial_payment,allowed_for_order_payment,allowed_for_invoice_payment,allowed_for_refund,allowed_for_customer_advance,allowed_for_wallet_topup,allowed_for_gift_card_topup,allowed_for_supplier_payment,allowed_for_expense_payment,display_order,icon,color) values
('CASH','Cash','نقداً','Physical cash received or paid at POS.','نقد فعلي يتم استلامه أو دفعه في نقطة البيع.','CASH','REAL_PAYMENT',true,false,false,false,false,false,false,true,false,false,false,false,true,false,true,true,true,true,true,true,true,true,true,true,10,'cash','#16a34a'),
('CARD','Card','بطاقة','Generic card payment through POS terminal or manual card flow.','دفع بالبطاقة عبر جهاز نقطة بيع أو إجراء يدوي.','CARD','REAL_PAYMENT',false,true,false,false,false,false,true,false,true,true,true,true,true,true,true,true,true,true,true,true,false,false,20,'credit-card','#2563eb'),
('BANK_TRANSFER','Bank Transfer','تحويل بنكي','Bank transfer payment confirmed manually or through bank integration.','دفع عبر تحويل بنكي يتم تأكيده يدوياً أو عبر تكامل بنكي.','BANK','REAL_PAYMENT',false,false,true,false,false,false,false,false,true,true,false,false,true,false,true,true,true,true,true,true,true,true,30,'banknote','#0f766e'),
('CHECK','Check','شيك','Check payment. Counts as paid only after clearance policy marks it completed.','دفع بشيك، ولا يعتبر مدفوعاً إلا بعد التصفية حسب السياسة.','CHECK','REAL_PAYMENT',false,false,false,true,false,false,false,false,true,true,false,false,true,false,true,true,true,true,false,false,true,true,40,'receipt','#64748b'),
('MOBILE_PAYMENT','Mobile Payment','دفع عبر الهاتف','Mobile payment channel such as QR payment or mobile banking when treated as real money.','قناة دفع عبر الهاتف مثل QR أو تحويل عبر تطبيق بنكي عندما تعد كأموال حقيقية.','MOBILE','REAL_PAYMENT',false,false,false,false,true,false,true,false,true,true,false,false,true,true,true,true,true,true,true,true,false,false,50,'smartphone','#9333ea'),
('PAYMENT_GATEWAY','Payment Gateway','بوابة دفع','External online payment gateway such as HyperPay, PayTabs, Stripe, or similar.','بوابة دفع إلكترونية خارجية مثل HyperPay أو PayTabs أو Stripe أو ما شابه.','GATEWAY','REAL_PAYMENT',false,false,false,false,false,true,true,false,true,true,true,true,true,true,true,true,true,true,true,true,false,false,60,'globe','#f97316')
