('REDUCE_PAYMENT','Reduce Payment Amount','تخفيض مبلغ الدفع','Reduce entered payment amount before posting/capture.','تخفيض مبلغ الدفع المدخل قبل الترحيل أو التحصيل.',true,true,true,true,true,true,false,false,true,false,false,false,false,false,false,false,false,null,false,false,10),
('RETURN_CASH_CHANGE','Return Cash Change','إرجاع الباقي نقداً','Return excess cash as change to customer.','إرجاع الزيادة النقدية كباقي للعميل.',true,false,false,false,false,false,false,true,false,false,false,false,false,false,false,false,false,null,false,false,20),
('VOID_OR_REFUND_EXCESS','Void or Refund Excess','إلغاء أو رد الزيادة','Void authorization or refund captured excess amount.','إلغاء التفويض أو رد المبلغ الزائد المحصل.',false,true,true,true,false,true,false,false,false,true,false,false,false,false,false,false,true,'order_payment:refund_excess',true,true,30),
('SAVE_AS_CUSTOMER_ADVANCE','Save as Customer Advance','حفظ كدفعة مقدمة','Convert excess amount to customer advance/deposit balance.','تحويل المبلغ الزائد إلى رصيد دفعة مقدمة للعميل.',true,true,true,true,true,true,false,false,false,false,true,false,false,false,false,false,true,'customer_advance:create',true,false,40),
('SAVE_AS_CUSTOMER_CREDIT','Save as Customer Credit','حفظ كرصيد عميل','Convert excess amount to customer credit balance.','تحويل المبلغ الزائد إلى رصيد عميل.',true,true,true,true,true,true,false,false,false,false,false,true,false,false,false,false,true,'customer_credit:create',true,false,50),
('RESTORE_STORED_VALUE','Restore Stored Value','استعادة القيمة المخزنة','Restore excess applied stored value back to its source.','استعادة القيمة المخزنة الزائدة إلى مصدرها.',false,false,false,false,false,false,true,false,false,false,false,false,true,false,false,false,false,null,false,false,60),
('ALLOCATE_TO_CUSTOMER_BALANCES','Manual Allocate to Customer Balances','توزيع يدوي على أرصدة العميل','Cashier manually allocates excess amount to customer open orders, AR invoices, statements, wallet, advance, or credit.','يقوم أمين الصندوق بتوزيع المبلغ الزائد يدوياً على طلبات أو فواتير أو كشوفات أو محفظة أو دفعات مقدمة أو أرصدة العميل.',true,true,true,true,true,true,false,false,false,false,false,false,false,true,false,true,false,null,false,false,70),
('AUTO_ALLOCATE_TO_CUSTOMER_BALANCES','Auto Allocate to Customer Balances','توزيع آلي على أرصدة العميل','System automatically allocates excess amount to oldest eligible customer balances according to tenant policy.','يقوم النظام بتوزيع المبلغ الزائد آلياً على أقدم أرصدة العميل المؤهلة حسب سياسة المنشأة.',true,true,true,true,true,true,false,false,false,false,false,false,false,true,true,true,false,null,false,false,80)
insert into public.sys_customer_receipt_allocation_mode_cd (allocation_mode,name,name2,description,description2,sort_by_due_date,sort_by_document_date,uses_target_priority,is_manual_only,display_order) values
('AUTO_OLDEST_DUE','Auto Oldest Due','آلي حسب الأقدم استحقاقاً','Automatically allocate by due date ascending, then document date.','توزيع آلي حسب تاريخ الاستحقاق تصاعدياً ثم تاريخ المستند.',true,false,true,false,10),
('AUTO_OLDEST_DOCUMENT','Auto Oldest Document','آلي حسب أقدم مستند','Automatically allocate by document date ascending.','توزيع آلي حسب تاريخ المستند تصاعدياً.',false,true,false,false,20),
('AUTO_PRIORITY_THEN_OLDEST','Auto Priority Then Oldest','آلي حسب الأولوية ثم الأقدم','Automatically allocate by configured target priority, then oldest due/document.','توزيع آلي حسب أولوية الهدف ثم الأقدم استحقاقاً أو مستنداً.',true,true,true,false,30),
('MANUAL_ONLY','Manual Only','يدوي فقط','No auto allocation; cashier must select targets manually.','لا يوجد توزيع آلي؛ يجب على أمين الصندوق اختيار الأهداف يدوياً.',false,false,false,true,40)
